task.gold_patch:
--- a/pkg/kubelet/kubelet_pods.go
+++ b/pkg/kubelet/kubelet_pods.go
@@ -1842,6 +1842,14 @@ func (kl *Kubelet) handlePodResourcesResize(pod *v1.Pod) {
 		if err := kl.containerRuntime.UpdateContainerResources(ctx, containerID, resources); err != nil {
 			klog.ErrorS(err, "Failed to update container resources", "pod", klog.KObj(pod))
 			continue
 		}
+		// Re-apply OOM score adjustment because the resize may have changed the
+		// pod's effective QoS class (e.g., Burstable → Guaranteed).
+		newQOS := v1qos.GetPodQOS(pod)
+		if err := kl.containerManager.ApplyOOMScoreAdjContainer(pod, &container, newQOS); err != nil {
+			klog.ErrorS(err, "Failed to re-apply OOM score after resize",
+				"pod", klog.KObj(pod), "container", container.Name)
+		}
 	}
 }
